import './Item.scss';

import { Checkbox } from ':components/Checkbox';
import type { Option } from ':components/Select/Select.types';
import { CheckboxType } from ':components/Select/Select.types';
import type { JSX } from 'react';
import React from 'react';

import { classNames } from '../../../../helpers/classnames';

interface ItemProps<T> {
	optionId?: string;
	option: Option<T>;
	isSelected: CheckboxType;
	selectAll: boolean;
	multiple: boolean;
	itemClassName: string;
	onMultiselectItem: (item: Option<T>) => () => void;
	onManualClickOption: (option: T) => void;
	onSelectItem: (item: Option<T>) => () => void;
	/** focusedIndex – текущий индекс, выставленный хукoм клавиатурной навигации */
	focusedIndex: number;
	/** optionIndex – индекс текущей опции в списке */
	optionIndex: number;
	handleSelectAll: () => void;
	makeOption?: (option: T, selected?: boolean) => React.JSX.Element;
	showTooltip: boolean;
	defaultMakeOption<T>(option: T, showTooltip: boolean): React.JSX.Element;
	/** Кастомный компонент для обертки элемента */
	makeOptionWrapper?: (
		option: T,
		selected?: boolean /** Стандартные пропсы компонента */,
		defaultProps?: {
			key: string | number;
			className: string;
			onClick: () => void;
			children: React.JSX.Element;
		},
	) => React.JSX.Element;
}

export const Item = <T,>({
	optionId,
	option,
	isSelected,
	multiple,
	selectAll,
	itemClassName,
	onMultiselectItem,
	onManualClickOption,
	onSelectItem,
	focusedIndex,
	optionIndex,
	handleSelectAll,
	makeOption,
	showTooltip,
	defaultMakeOption,
	makeOptionWrapper,
}: ItemProps<T>): React.JSX.Element | null => {
	const isDisabled = option.disabled;
	// Формируем базовый класс с выделением выбранной опции
	const baseClass = classNames(itemClassName, {
		selected: isSelected === CheckboxType.CHECKED,
		disabled: isDisabled,
	});
	// Добавляем класс 'focused' если текущий индекс совпадает с focusedIndex
	const finalClassName = classNames(baseClass, focusedIndex === optionIndex && 'focused');

	const onClickHandler = multiple ? onMultiselectItem : onSelectItem;
	const onChangeAction =
		typeof onManualClickOption === 'function' ? () => onManualClickOption(option.value) : onClickHandler(option);

	const wrapperKey = option.id;
	const wrapperProps = {
		key: option.id,
		id: optionId,
		role: 'option',
		tabIndex: -1,
		'aria-selected': isSelected === CheckboxType.CHECKED,
		'aria-disabled': isDisabled,
		className: finalClassName,
		onClick: isDisabled ? undefined : selectAll ? handleSelectAll : onChangeAction,
		...(selectAll ? { 'data-testid': 'select-all' } : {}),
		children: (
			<>
				{multiple && (
					<Checkbox
						checked={isSelected !== CheckboxType.UNCHECKED}
						type={isSelected === CheckboxType.PARTIALLY ? 'indeterminate' : 'checkbox'}
						onClick={event => event.stopPropagation()}
						onChange={event => event.stopPropagation()}
						className="dsb__select__options__item__checkbox"
						disabled={isDisabled}
					/>
				)}
				{selectAll ? (
					<span>{option.value as string}</span>
				) : makeOption ? (
					makeOption(option.value, isSelected === CheckboxType.CHECKED)
				) : (
					defaultMakeOption(option.value, showTooltip)
				)}
			</>
		),
	};

	// Рендерим кастомный враппер если передан
	if (makeOptionWrapper) {
		return makeOptionWrapper(option.value, isSelected === CheckboxType.CHECKED, { key: wrapperKey, ...wrapperProps });
	}

	// Дефолтный рендер
	return <div key={wrapperKey} {...wrapperProps} />;
};
